def svg_to_png(svg_path, png_path, width=800):
    """使用cairosvg将SVG转换为PNG"""
    try:
        import cairosvg
        cairosvg.svg2png(url=svg_path, write_to=png_path, output_width=width)
        return True
    except ImportError:
        # 如果cairosvg不可用，尝试使用Inkscape
        try:
            subprocess.run([
                'inkscape',
                svg_path,
                '--export-filename=' + png_path,
                '--export-width=' + str(width)
            ], check=True, capture_output=True)
            return True
        except:
            return False

